import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

export default function TrustSection() {
  const sectionRef = useRef(null);
  const [p, setP] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const scrolled = -el.getBoundingClientRect().top;
      const total = el.offsetHeight - window.innerHeight;
      setP(Math.max(0, Math.min(1, scrolled / (total * 0.88))));
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const lp = (start, end) => ease(clamp((p - start) / (end - start), 0, 1));

  const l0 = lp(0.00, 0.12); // "Trust,"
  const l1 = lp(0.10, 0.22); // "however is fragile."
  const l3 = lp(0.28, 0.42); // "One news headline."
  const l4 = lp(0.40, 0.54); // "One breach"
  const l5 = lp(0.52, 0.66); // "One bad experience."
  const l6 = lp(0.64, 0.78); // footer line

  const ghost1 = lp(0.24, 0.38);
  const ghost2 = lp(0.46, 0.60);

  return (
    <div ref={sectionRef} style={{ height: "380vh", position: "relative", background: "#fff" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh",
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        overflow: "hidden",
        padding: "0 6vw",
      }}>

        {/* ── Main big text block ─────────────────────────────────── */}
        <div style={{
          position: "relative",
          textAlign: "center",
          zIndex: 1,
          lineHeight: 1.08,
        }}>

          {/* Trust, */}
          <div style={{
            opacity: l0,
            transform: `translateY(${(1 - l0) * 50}px)`,
          }}>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(64px,11vw,140px)",
              fontWeight: 900, color: "#1a3a6b",
              display: "block", lineHeight: 1.0,
            }}>Trust,</span>
          </div>

          {/* however is  fragile. — same line, matching Figma */}
          <div style={{
            opacity: l1,
            transform: `translateY(${(1 - l1) * 50}px)`,
            display: "flex", alignItems: "baseline", justifyContent: "center",
            gap: "0.25em", flexWrap: "wrap",
          }}>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(48px,8vw,110px)",
              fontWeight: 400, color: "#aaa",
              lineHeight: 1.0,
            }}>however is</span>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(48px,8vw,110px)",
              fontWeight: 900, color: "#1a1a1a",
              lineHeight: 1.05,
            }}>fragile.</span>
          </div>

          {/* One news headline. */}
          <div style={{
            opacity: l3,
            transform: `translateY(${(1 - l3) * 50}px)`,
          }}>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 900, color: "#e53e3e",
              display: "inline",
            }}>One </span>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 400, color: "#999",
              display: "inline",
            }}>news headline.</span>
          </div>

          {/* One breach */}
          <div style={{
            opacity: l4,
            transform: `translateY(${(1 - l4) * 50}px)`,
          }}>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 900, color: "#e53e3e",
              display: "inline",
            }}>One </span>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 400, color: "#999",
              display: "inline",
            }}>breach</span>
          </div>

          {/* One bad experience. */}
          <div style={{
            opacity: l5,
            transform: `translateY(${(1 - l5) * 50}px)`,
          }}>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 900, color: "#e53e3e",
              display: "inline",
            }}>One </span>
            <span style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(40px,7vw,100px)",
              fontWeight: 400, color: "#999",
              display: "inline",
            }}>bad experience.</span>
          </div>

          {/* Footer */}
          <div style={{
            marginTop: 28,
            opacity: l6,
            transform: `translateY(${(1 - l6) * 30}px)`,
          }}>
            <p style={{
              fontSize: "clamp(14px,1.2vw,20px)",
              color: "#555", lineHeight: 1.6,
            }}>
              is all it takes to undo years of hard-earned customer confidence.
            </p>
          </div>
        </div>

        {/* ── Ghost overlay 1 — left, overlaps the text like in Figma ── */}
        <div style={{
          position: "absolute",
          left: "4%", top: "34%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(255,255,255,0.72)",
          borderRadius: 6,
          padding: "12px 16px",
          maxWidth: 240,
          opacity: ghost1,
          transform: `translateX(${(1 - ghost1) * -28}px)`,
        }}>
          <p style={{
            fontSize: 13, color: "#333", lineHeight: 1.65,
            fontFamily: "'Inter',sans-serif",
            margin: 0,
          }}>
            When speed and scale take priority, due diligence
            slips and blind spots widen. That's exactly what is
            happening in the gig economy today.
          </p>
        </div>

        {/* ── Ghost overlay 2 — right, overlaps the lower text ── */}
        <div style={{
          position: "absolute",
          right: "3%", bottom: "22%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(255,255,255,0.72)",
          borderRadius: 6,
          padding: "12px 16px",
          maxWidth: 260,
          opacity: ghost2,
          transform: `translateX(${(1 - ghost2) * 28}px)`,
        }}>
          <p style={{
            fontSize: 13, color: "#333", lineHeight: 1.65,
            fontFamily: "'Inter',sans-serif",
            margin: 0,
          }}>
            Identity swaps, impersonation, and
            hidden criminal histories do more than
            disrupt operations. They put safety,
            credibility, and customer trust at risk.
          </p>
        </div>

      </div>
    </div>
  );
}
